  render: function Authentication() {
    const [isAuthenticating, setIsAuthenticating] = useState(false);
    const [authenticated, setAuthenticated] = useState(false);
    const [hasUserDetails, setHasUserDetails] = useState(false);
    const handleSignIn = async () => {
      setIsAuthenticating(true);
      setTimeout(() => {
        setIsAuthenticating(false);
        setAuthenticated(true);
        // Fake a loading screen
        setTimeout(() => {
          setHasUserDetails(true);
        }, 1000);
      }, 3000);
    };
    const handleSignOut = async () => {
      setAuthenticated(false);
    };
    return <Fragment>
                <SkipLinks links={[{
        href: '#main-content',
        label: 'Skip to main content'
      }]} />
                <AppLayout activePath="/" handleSignIn={handleSignIn} handleSignOut={handleSignOut} {...authenticated ? hasUserDetails ? {
        userName: 'Toto Wolff',
        userOrganisation: 'Orange Meat Works',
        unreadMessageCount: 6
      } : {} : {
        mode: 'site'
      }}>
                    <PageContent>
                        <Prose>
                            <h1>Page heading</h1>
                        </Prose>
                    </PageContent>
                </AppLayout>
                {isAuthenticating && <LoadingBlanket fullScreen label="You are being redirected to myGovID" />}
            </Fragment>;
  }
